SELECT architecture
FROM model_architectures
WHERE model_id = 1;

SELECT user_id
FROM user_project
WHERE project_id = 1 AND role = 'data analyst';

SELECT COUNT(*) AS total_models
FROM model_project
WHERE project_id = 1;

SELECT u.name, u.email, u.role 
FROM users u
JOIN user_project up ON u.user_id = up.user_id;

SELECT COUNT(*) AS total_holdout_evaluations
FROM evaluations
WHERE evaluation_type = 'holdout';

SELECT hyperparameter, value
FROM model_hyperparameters
WHERE model_id = 1;
